.darma-loader-darma-custom-533 {color: var(--loader-color, #7c3aed);
   display: inline-flex;
   gap: 10px;
}
.darma-loader-darma-custom-533:before, .darma-loader-darma-custom-533:after  {
  content: "";
   height: 20px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: linear-gradient(var(--loader-secondary-color, #c084fc) 0 0) top/100% 0% no-repeat, radial-gradient(farthest-side,currentColor 95%,#0000) 50%/8px 8px no-repeat currentColor;
   animation: darma-loader-darma-custom-533-l9 4s infinite ease-in;
}
@keyframes darma-loader-darma-custom-533-l9  {
  0% {background-size:100% 0%,8px 8px;
  background-position:top, 50% 50%}
80% {background-size:100% 70%,8px 8px;
  background-position:top, 50% 70%}
84%, 100%{background-size:100% 0%,8px 8px;
  background-position:top, 50% 50%}
}

